from flask import Flask, send_from_directory, abort, request
from werkzeug.utils import secure_filename
import os
import re

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = 'uploads'
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

# Ensure uploads directory exists
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

# Legacy filename mappings and patterns
LEGACY_FILENAME_MAPPINGS = {
    'old_logo.png': 'logo_new.png',
    'company_profile.pdf': 'company-profile-2024.pdf',
    'terms.txt': 'terms_and_conditions.txt',
}

def normalize_legacy_filename(filename):
    """Convert legacy filename formats to current format"""
    # Handle direct mappings first
    if filename in LEGACY_FILENAME_MAPPINGS:
        return LEGACY_FILENAME_MAPPINGS[filename]
    
    # Legacy pattern 1: Convert underscores to hyphens (old_file_name.ext -> old-file-name.ext)
    legacy_underscore = filename.replace('_', '-')
    if os.path.exists(os.path.join(app.config['UPLOAD_FOLDER'], legacy_underscore)):
        return legacy_underscore
    
    # Legacy pattern 2: Handle uppercase extensions (.PDF -> .pdf)
    name, ext = os.path.splitext(filename)
    legacy_lower_ext = name + ext.lower()
    if ext != ext.lower() and os.path.exists(os.path.join(app.config['UPLOAD_FOLDER'], legacy_lower_ext)):
        return legacy_lower_ext
    
    # Legacy pattern 3: Handle space-to-underscore conversion (my file.pdf -> my_file.pdf)
    legacy_space_to_underscore = filename.replace(' ', '_')
    if ' ' in filename and os.path.exists(os.path.join(app.config['UPLOAD_FOLDER'], legacy_space_to_underscore)):
        return legacy_space_to_underscore
    
    # Legacy pattern 4: Handle versioned files (file_v1.pdf -> file_v2.pdf, find latest)
    version_match = re.match(r'(.+)_v(\d+)(\.\w+)$', filename)
    if version_match:
        base_name, version, extension = version_match.groups()
        # Try to find higher versions
        for v in range(int(version), 100):
            versioned_file = f"{base_name}_v{v}{extension}"
            if os.path.exists(os.path.join(app.config['UPLOAD_FOLDER'], versioned_file)):
                return versioned_file
    
    # Legacy pattern 5: Handle date-prefixed files (YYYYMMDD_filename.ext -> filename.ext or vice versa)
    date_prefix_match = re.match(r'(\d{8})_(.+)', filename)
    if date_prefix_match:
        _, name_without_date = date_prefix_match.groups()
        if os.path.exists(os.path.join(app.config['UPLOAD_FOLDER'], name_without_date)):
            return name_without_date
    else:
        # Try adding date prefixes
        for entry in os.listdir(app.config['UPLOAD_FOLDER']):
            if re.match(r'\d{8}_' + re.escape(filename), entry):
                return entry
    
    # Return original if no legacy pattern matched
    return filename

def find_file_case_insensitive(filename):
    """Find file with case-insensitive matching for backward compatibility"""
    upload_folder = app.config['UPLOAD_FOLDER']
    
    # First try exact match
    if os.path.exists(os.path.join(upload_folder, filename)):
        return filename
    
    # Try case-insensitive search
    filename_lower = filename.lower()
    for entry in os.listdir(upload_folder):
        if entry.lower() == filename_lower:
            return entry
    
    return None

@app.route('/uploads/<path:filename>')
def serve_upload(filename):
    """Serve static files from uploads directory with legacy support"""
    try:
        # Security: prevent directory traversal
        filename = secure_filename(filename)
        
        # Step 1: Try to find the file as-is
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        if os.path.exists(filepath) and os.path.isfile(filepath):
            return send_from_directory(app.config['UPLOAD_FOLDER'], filename)
        
        # Step 2: Apply legacy filename normalization
        normalized_filename = normalize_legacy_filename(filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], normalized_filename)
        if os.path.exists(filepath) and os.path.isfile(filepath):
            return send_from_directory(app.config['UPLOAD_FOLDER'], normalized_filename)
        
        # Step 3: Try case-insensitive matching
        found_filename = find_file_case_insensitive(filename)
        if found_filename:
            return send_from_directory(app.config['UPLOAD_FOLDER'], found_filename)
        
        # Step 4: Try case-insensitive matching on normalized filename
        found_filename = find_file_case_insensitive(normalized_filename)
        if found_filename:
            return send_from_directory(app.config['UPLOAD_FOLDER'], found_filename)
        
        # File not found
        abort(404)
        
    except Exception as e:
        abort(404)

@app.route('/legacy-uploads/<path:filename>')
def serve_legacy_upload(filename):
    """Dedicated endpoint for legacy file requests"""
    # Apply all legacy transformations aggressively
    filename = secure_filename(filename)
    
    # Chain legacy transformations
    filename = filename.replace(' ', '_')
    filename = filename.replace('_', '-')
    name, ext = os.path.splitext(filename)
    filename = name + ext.lower()
    
    # Try to serve
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    if os.path.exists(filepath) and os.path.isfile(filepath):
        return send_from_directory(app.config['UPLOAD_FOLDER'], filename)
    
    # Fallback to main handler
    return serve_upload(filename)

